def _route_smoke_live_result(probe, staff_user):
    client = Client()
    if probe["client"] == "staff":
        client.force_login(staff_user)
    response = client.get(probe["path"])
    content_type = response.get("Content-Type", "")
    body = response.content.decode(errors="ignore")[:500]
    status_ok = response.status_code == probe["expected_status"]
    content_type_ok = content_type.startswith(probe["expected_content_type"])
    marker = probe.get("robots_marker", "")
    robots_ok = True if not marker else marker in body
    passed = status_ok and content_type_ok and robots_ok
    return {"path": probe["path"], "client": probe["client"], "expected_status": probe["expected_status"], "status_code": response.status_code, "expected_content_type": probe["expected_content_type"], "content_type": content_type, "robots_marker": marker, "status_ok": status_ok, "content_type_ok": content_type_ok, "robots_ok": robots_ok, "passed": passed, "launch_blocker": not passed, "redirect_location": response.get("Location", ""), "response_bytes": len(response.content), "snippet": body}


