def _release_readiness_inventory(results):
    public_paths = [result["path"] for result in results if result["client"] == "public"]
    admin_paths = [result["path"] for result in results if result["client"] == "staff"]
    machine_readable_paths = [
        result["path"]
        for result in results
        if any(token in result["content_type"] for token in ["text/plain", "application/xml", "text/markdown", "application/json", "text/csv"])
    ]
    noindex_held_paths = [result["path"] for result in results if result.get("robots_marker") == "noindex,follow"]
    indexable_submit_paths = [result["path"] for result in results if result.get("robots_marker") == "index,follow"]
    return {
        "critical_paths": [result["path"] for result in results],
        "public_paths": public_paths,
        "private_paths": [path for path in public_paths if path.startswith("/business/")],
        "admin_paths": admin_paths + ["/admin/launch-qa/blockers.json"],
        "machine_readable_paths": machine_readable_paths,
        "indexable_submit_paths": indexable_submit_paths,
        "noindex_held_paths": noindex_held_paths,
    }


