@staff_member_required
def freshness_dashboard(request):
    cutoff = timezone.now() - timezone.timedelta(days=90)
    stale_companies = Company.objects.filter(last_verified_at__lt=cutoff).order_by("last_verified_at", "name")[:100]
    stale_sources = ExternalSource.objects.filter(captured_at__lt=cutoff).select_related("company").order_by("captured_at", "company__name")[:100]
    stale_guides = Guide.objects.filter(status=Guide.Status.PUBLISHED, last_verified_at__lt=cutoff).select_related("category").order_by("last_verified_at", "title")[:100]
    return render(
        request,
        "launchqa/freshness_dashboard.html",
        {
            "page_title": "Freshness dashboard",
            "robots_meta": "noindex,follow",
            "cutoff": cutoff,
            "stale_companies": stale_companies,
            "stale_sources": stale_sources,
            "stale_guides": stale_guides,
        },
    )


@staff_member_required
def seo_audit_export_csv(request):
    response = HttpResponse(content_type="text/csv; charset=utf-8")
    response["Content-Disposition"] = 'attachment; filename="seo-page-audit.csv"'
    writer = csv.DictWriter(
        response,
        fieldnames=[
            "url",
            "page_type",
            "index_status",
            "http_status",
            "is_empty_profile",
            "has_launch_risk",
            "submitted_at",
            "indexed_at",
            "last_checked_at",
            "notes",
        ],
    )
    writer.writeheader()
    for row in IndexingMonitorURL.objects.all():
        writer.writerow(
            {
                "url": row.url,
                "page_type": row.page_type,
                "index_status": row.index_status,
                "http_status": row.http_status or "",
                "is_empty_profile": row.is_empty_profile,
                "has_launch_risk": row.has_launch_risk,
                "submitted_at": row.submitted_at.isoformat() if row.submitted_at else "",
                "indexed_at": row.indexed_at.isoformat() if row.indexed_at else "",
                "last_checked_at": row.last_checked_at.isoformat() if row.last_checked_at else "",
                "notes": row.notes,
            }
        )
    return response

